function getEmergencyStatus(id) {
  try {
    const raw = localStorage.getItem(`emergency_status_${id}`);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (Date.now() - parsed.setAt > 72 * 60 * 60 * 1e3) {
      localStorage.removeItem(`emergency_status_${id}`);
      return null;
    }
    return parsed.status;
  } catch {
    return null;
  }
}
function getSelfReported(id) {
  try {
    const raw = localStorage.getItem(`self_live_${id}`);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (Date.now() - parsed.setAt > 4 * 60 * 60 * 1e3) {
      localStorage.removeItem(`self_live_${id}`);
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}
function setSelfReported(id, live) {
  localStorage.setItem(
    `self_live_${id}`,
    JSON.stringify({ live, setAt: Date.now() })
  );
}
function clearSelfReported(id) {
  localStorage.removeItem(`self_live_${id}`);
}
